using System.Text.Json;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this agent.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient through the MEAI abstraction ---
IChatClient innerClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Set up tools ---
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

var notebook = new Notebook();
var webSearch = new WebSearchTool(httpClient);

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Create the agent ---
var agent = new ChatClientAgent(
    innerClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "Researches topics by searching the web and taking notes",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = tools,
        },
    });

// --- Prompt for a research topic ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent ---
var session = await agent.CreateSessionAsync("research-session");

var response = await agent.RunAsync(
    $"""
    Research the following topic and provide a comprehensive summary: {topic}

    Follow this workflow:
    1. Search the web for information about the topic using multiple queries
    2. Fetch relevant pages to gather detailed information
    3. Take notes on each key finding using the note-taking tool
    4. After gathering sufficient information, retrieve all your notes
    5. Synthesize your notes into a well-structured summary with key takeaways
    """,
    session);

Console.WriteLine("=== Research Summary ===\n");
Console.WriteLine(response.Text);

// --- Web search tool ---
sealed class WebSearchTool(HttpClient httpClient)
{
    [Description("Search the web for information on a given query. Returns a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: {query}");

        var encodedQuery = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encodedQuery}";

        var request = new HttpRequestMessage(HttpMethod.Get, url);
        request.Headers.Add("Accept", "text/html");

        var html = await httpClient.GetStringAsync(url, cancellationToken);

        // Extract search results from DuckDuckGo HTML response
        var results = new StringBuilder();
        var resultPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]+href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
            RegexOptions.Singleline);

        var matches = resultPattern.Matches(html);
        var count = 0;
        foreach (Match match in matches)
        {
            if (count >= 8) break;
            count++;

            var title = StripHtml(match.Groups["title"].Value);
            var resultUrl = ExtractUrl(match.Groups["url"].Value);
            var snippet = StripHtml(match.Groups["snippet"].Value);

            results.AppendLine($"[{count}] {title}");
            results.AppendLine($"    URL: {resultUrl}");
            results.AppendLine($"    {snippet}");
            results.AppendLine();
        }

        return count > 0
            ? results.ToString()
            : "No results found. Try a different search query.";
    }

    [Description("Fetch the text content of a web page at the given URL. Returns the page text (truncated to ~4000 characters).")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL of the page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  📄 Fetching: {url}");

        try
        {
            var html = await httpClient.GetStringAsync(url, cancellationToken);
            var text = StripHtml(html);

            // Collapse whitespace and trim to a useful length
            text = Regex.Replace(text, @"\s+", " ").Trim();
            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "... [truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Page content could not be extracted."
                : text;
        }
        catch (HttpRequestException ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(html, @"<script[^>]*>.*?</script>", " ", RegexOptions.Singleline);
        text = Regex.Replace(text, @"<style[^>]*>.*?</style>", " ", RegexOptions.Singleline);
        text = Regex.Replace(text, @"<[^>]+>", " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        return text.Trim();
    }

    private static string ExtractUrl(string duckDuckGoRedirect)
    {
        // DuckDuckGo wraps URLs in a redirect; extract the actual destination
        var match = Regex.Match(duckDuckGoRedirect, @"uddg=(?<url>[^&]+)");
        if (match.Success)
            return Uri.UnescapeDataString(match.Groups["url"].Value);
        return duckDuckGoRedirect;
    }
}

